noncompliant:
#include <functional>

int add(int a, int b, int c) {
  return a + b + c;
}

void example() {
  auto bound_func = std::bind(add, std::placeholders::_1, 10, std::placeholders::_2);
  int result = bound_func(5, 15); // Hard to understand
}

// Using boost::bind is also discouraged
auto boost_bound = boost::bind(add, _1, 10, _2);

compliant:
#include <functional>

int add(int a, int b, int c) {
  return a + b + c;
}

void example() {
  // Use lambda instead of bind - clearer and more flexible
  auto lambda_func = [](int a, int c) { return add(a, 10, c); };
  int result = lambda_func(5, 15); // Much clearer
}

// Or capture specific values
void example2() {
  int middle_value = 10;
  auto captured_lambda = [middle_value](int a, int c) {
    return add(a, middle_value, c);
  };
}
